</head>
<body>
    <h1>Singly Linked List Visualizer</h1>

    <div class="controls">
        <div class="control-group">
            <input type="number" id="insertValue" placeholder="Value" min="0">
            <button id="insertHeadBtn">Insert at Head</button>
            <button id="insertTailBtn">Insert at Tail</button>
        </div>
        <div class="control-group">
            <input type="number" id="deleteValue" placeholder="Value" min="0">
            <button id="deleteBtn">Delete by Value</button>
        </div>
        <div class="control-group">
            <input type="number" id="searchValue" placeholder="Value" min="0">
            <button id="searchBtn">Search</button>
        </div>
    </div>

    <div class="messages" id="messages"></div>

    <div class="visualization-container">
        <svg id="linkedListSvg" viewBox="0 0 1000 150" preserveAspectRatio="xMidYMid meet">
            <defs>
                <marker id="arrowhead" markerWidth="10" markerHeight="7" refX="0" refY="3.5" orient="auto">
                    <polygon points="0 0, 10 3.5, 0 7" />
                </marker>
            </defs>
            <!-- List elements will be drawn here by JavaScript -->
        </svg>
        <div id="emptyListMessage" class="empty-list-message" style="display: none;">List is Empty</div>
    </div>

    <script>
        // --- Configuration Constants ---
        const NODE_WIDTH = 80;
        const NODE_HEIGHT = 40;
        const NODE_SPACING = 50; // Space between nodes
        const ARROW_LENGTH = 30; // Length of the arrow line segment
        const SVG_HEIGHT = 150;
        const HIGHLIGHT_DURATION = 1000; // ms

        // --- DOM Elements ---
        const linkedListSvg = document.getElementById('linkedListSvg');
        const emptyListMessage = document.getElementById('emptyListMessage');
        const messagesDiv = document.getElementById('messages');

        const insertValueInput = document.getElementById('insertValue');
        const insertHeadBtn = document.getElementById('insertHeadBtn');
        const insertTailBtn = document.getElementById('insertTailBtn');

        const deleteValueInput = document.getElementById('deleteValue');
        const deleteBtn = document.getElementById('deleteBtn');

        const searchValueInput = document.getElementById('searchValue');
        const searchBtn = document.getElementById('searchBtn');

        // --- Helper for messages ---
        let messageTimeout;
        function displayMessage(text, type = 'info') {
            clearTimeout(messageTimeout);
            messagesDiv.textContent = text;
            messagesDiv.className = `messages message ${type}`;
            messageTimeout = setTimeout(() => {
                messagesDiv.textContent = '';
                messagesDiv.className = 'messages';
            }, 3000); // Message disappears after 3 seconds
        }

        // --- Node Class ---
        class Node {
            constructor(value) {
                this.value = value;
                this.next = null;
            }
        }

        // --- Singly LinkedList Class ---
        class LinkedList {
            constructor() {
                this.head = null;
                this.size = 0;
            }

            // Insert at the beginning
            insertAtHead(value) {
                const newNode = new Node(value);
                newNode.next = this.head;
                this.head = newNode;
                this.size++;
                displayMessage(`Inserted ${value} at head.`, 'success');
            }

            // Insert at the end
            insertAtTail(value) {
                const newNode = new Node(value);
                if (!this.head) {
                    this.head = newNode;
                } else {
                    let current = this.head;
                    while (current.next) {
                        current = current.next;
                    }
                    current.next = newNode;
                }
                this.size++;
                displayMessage(`Inserted ${value} at tail.`, 'success');
            }

            // Delete by value
            deleteByValue(value) {
                if (!this.head) {
                    displayMessage(`Cannot delete ${value}. List is empty.`, 'error');
                    return false;
                }

                if (this.head.value === value) {
                    this.head = this.head.next;
                    this.size--;
                    displayMessage(`Deleted ${value}.`, 'success');
                    return true;
                }

                let current = this.head;
                let previous = null;
                while (current && current.value !== value) {
                    previous = current;
                    current = current.next;
                }

                if (current) {
                    previous.next = current.next;
                    this.size--;
                    displayMessage(`Deleted ${value}.`, 'success');
                    return true;
                } else {
                    displayMessage(`${value} not found in the list.`, 'error');
                    return false;
                }
            }

            // Search by value
            search(value) {
                if (!this.head) {
                    displayMessage(`Cannot search ${value}. List is empty.`, 'error');
                    return null;
                }

                let current = this.head;
                let foundNode = null;
                let count = 0;
                while (current) {
                    if (current.value === value) {
                        foundNode = { node: current, index: count };
                        break;
                    }
                    current = current.next;
                    count++;
                }

                if (foundNode) {
                    displayMessage(`${value} found in the list.`, 'success');
                } else {
                    displayMessage(`${value} not found in the list.`, 'error');
                }
                return foundNode;
            }

            isEmpty() {
                return this.size === 0;
            }
        }

        // --- Visualization Logic ---
        const linkedList = new LinkedList();

        function renderList() {
            linkedListSvg.innerHTML = `
                <defs>
                    <marker id="arrowhead" markerWidth="10" markerHeight="7" refX="0" refY="3.5" orient="auto">
                        <polygon points="0 0, 10 3.5, 0 7" />
                    </marker>
                </defs>
            `; // Clear previous drawing and re-add arrowhead def

            if (linkedList.isEmpty()) {
                emptyListMessage.style.display = 'block';
                linkedListSvg.style.display = 'none';
                return;
            } else {
                emptyListMessage.style.display = 'none';
                linkedListSvg.style.display = 'block';
            }

            let current = linkedList.head;
            let x = 20; // Starting X position for the first node
            const y = SVG_HEIGHT / 2 - NODE_HEIGHT / 2; // Vertically center nodes

            // Calculate total width needed for viewBox
            const totalWidth = linkedList.size * (NODE_WIDTH + NODE_SPACING) - NODE_SPACING + 40; // Add padding

            // Update viewBox to fit content dynamically
            linkedListSvg.setAttribute('viewBox', `0 0 ${Math.max(1000, totalWidth)} ${SVG_HEIGHT}`);

            while (current) {
                // Draw Node Rectangle
                const rect = document.createElementNS('http://www.w3.org/2000/svg', 'rect');
                rect.setAttribute('x', x);
                rect.setAttribute('y', y);
                rect.setAttribute('width', NODE_WIDTH);
                rect.setAttribute('height', NODE_HEIGHT);
                rect.setAttribute('rx', 5); // Rounded corners
                rect.setAttribute('ry', 5);
                rect.classList.add('node-rect');
                rect.dataset.value = current.value; // Store value for easy lookup
                linkedListSvg.appendChild(rect);

                // Draw Node Text (Value)
                const text = document.createElementNS('http://www.w3.org/2000/svg', 'text');
                text.setAttribute('x', x + NODE_WIDTH / 2);
                text.setAttribute('y', y + NODE_HEIGHT / 2 + 5); // Adjust for vertical centering
                text.setAttribute('text-anchor', 'middle');
                text.classList.add('node-text');
                text.textContent = current.value;
                linkedListSvg.appendChild(text);

                // Draw Arrow if not the last node
                if (current.next) {
                    const line = document.createElementNS('http://www.w3.org/2000/svg', 'line');
                    line.setAttribute('x1', x + NODE_WIDTH);
                    line.setAttribute('y1', y + NODE_HEIGHT / 2);
                    line.setAttribute('x2', x + NODE_WIDTH + NODE_SPACING - ARROW_LENGTH); // End before arrow head
                    line.setAttribute('y2', y + NODE_HEIGHT / 2);
                    line.classList.add('arrow-line');
                    linkedListSvg.appendChild(line);

                    // Move to next node's starting position
                    x += NODE_WIDTH + NODE_SPACING;
                } else {
                    // Last node: Draw "NULL" or "X" or just end
                    const nullText = document.createElementNS('http://www.w3.org/2000/svg', 'text');
                    nullText.setAttribute('x', x + NODE_WIDTH + (NODE_SPACING / 2));
                    nullText.setAttribute('y', y + NODE_HEIGHT / 2 + 5);
                    nullText.setAttribute('text-anchor', 'middle');
                    nullText.classList.add('node-text');
                    nullText.textContent = 'NULL';
                    nullText.style.fill = '#e74c3c';
                    linkedListSvg.appendChild(nullText);
                }

                current = current.next;
            }
        }

        function highlightNode(nodeValue) {
            const rects = linkedListSvg.querySelectorAll(`.node-rect[data-value="${nodeValue}"]`);
            if (rects.length > 0) {
                rects.forEach(rect => {
                    rect.classList.add('highlight');
                    setTimeout(() => {
                        rect.classList.remove('highlight');
                    }, HIGHLIGHT_DURATION);
                });
            }
        }

        // --- Event Listeners ---
        insertHeadBtn.addEventListener('click', () => {
            const value = parseInt(insertValueInput.value);
            if (!isNaN(value)) {
                linkedList.insertAtHead(value);
                renderList();
                insertValueInput.value = '';
            } else {
                displayMessage('Please enter a valid number for insertion.', 'error');
            }
        });

        insertTailBtn.addEventListener('click', () => {
            const value = parseInt(insertValueInput.value);
            if (!isNaN(value)) {
                linkedList.insertAtTail(value);
                renderList();
                insertValueInput.value = '';
            } else {
                displayMessage('Please enter a valid number for insertion.', 'error');
            }
        });

        deleteBtn.addEventListener('click', () => {
            const value = parseInt(deleteValueInput.value);
            if (!isNaN(value)) {
                linkedList.deleteByValue(value);
                renderList();
                deleteValueInput.value = '';
            } else {
                displayMessage('Please enter a valid number for deletion.', 'error');
            }
        });

        searchBtn.addEventListener('click', () => {
            const value = parseInt(searchValueInput.value);
            if (!isNaN(value)) {
                const result = linkedList.search(value);
                if (result) {
                    highlightNode(result.node.value);
                }
            } else {
                displayMessage('Please enter a valid number for search.', 'error');
            }
        });

        // Initial render
        renderList();

        // Add some initial nodes for demonstration
        linkedList.insertAtTail(10);
        linkedList.insertAtTail(20);
        linkedList.insertAtHead(5);
        renderList();
        displayMessage('Welcome! Try inserting, deleting, or searching for nodes.', 'info');
    </script>
</body>
</html>
```

