<body>

    <h1>Singly Linked List Visualizer</h1>

    <div class="controls">
        <div class="control-group">
            <input type="number" id="insertValue" placeholder="Value to insert">
            <button onclick="insertAtHead()">Insert at Head</button>
            <button onclick="insertAtTail()">Insert at Tail</button>
        </div>
        <div class="control-group">
            <input type="number" id="deleteValue" placeholder="Value to delete">
            <button class="delete" onclick="deleteByValue()">Delete by Value</button>
        </div>
        <div class="control-group">
            <input type="number" id="searchValue" placeholder="Value to search">
            <button class="search" onclick="searchByValue()">Search</button>
        </div>
    </div>

    <div class="visualization-container">
        <div class="list-nodes" id="listNodesContainer">
            <p class="empty-list-message" id="emptyMessage">List is empty.</p>
        </div>
        <svg class="svg-container" id="svgArrows"></svg>
    </div>

    <div class="svg-defs">
        <svg width="0" height="0">
            <defs>
                <marker id="arrowhead" markerWidth="10" markerHeight="7" refX="0" refY="3.5" orient="auto">
                    <polygon points="0 0, 10 3.5, 0 7" fill="#34495e" />
                </marker>
            </defs>
        </svg>
    </div>

    <script>
        class Node {
            constructor(value) {
                this.value = value;
                this.next = null;
            }
        }

        class LinkedList {
            constructor() {
                this.head = null;
                this.size = 0;
            }

            insertAtHead(value) {
                const newNode = new Node(value);
                newNode.next = this.head;
                this.head = newNode;
                this.size++;
            }

            insertAtTail(value) {
                const newNode = new Node(value);
                if (!this.head) {
                    this.head = newNode;
                } else {
                    let current = this.head;
                    while (current.next) {
                        current = current.next;
                    }
                    current.next = newNode;
                }
                this.size++;
            }

            deleteByValue(value) {
                if (!this.head) {
                    return false; // List is empty
                }

                if (this.head.value === value) {
                    this.head = this.head.next;
                    this.size--;
                    return true;
                }

                let current = this.head;
                while (current.next && current.next.value !== value) {
                    current = current.next;
                }

                if (current.next && current.next.value === value) {
                    current.next = current.next.next;
                    this.size--;
                    return true;
                }
                return false; // Value not found
            }

            search(value) {
                if (!this.head) {
                    return null;
                }
                let current = this.head;
                while (current) {
                    if (current.value === value) {
                        return current;
                    }
                    current = current.next;
                }
                return null; // Value not found
            }

            toArray() {
                const arr = [];
                let current = this.head;
                while (current) {
                    arr.push(current.value);
                    current = current.next;
                }
                return arr;
            }
        }

        const linkedList = new LinkedList();
        const listNodesContainer = document.getElementById('listNodesContainer');
        const emptyMessage = document.getElementById('emptyMessage');
        const svgArrows = document.getElementById('svgArrows');

        function renderList() {
            listNodesContainer.innerHTML = '';
            svgArrows.innerHTML = ''; // Clear existing arrows

            if (linkedList.size === 0) {
                emptyMessage.style.display = 'block';
                return;
            } else {
                emptyMessage.style.display = 'none';
            }

            let current = linkedList.head;
            let prevNodeElement = null;
            let nodeElements = []; // Store references to rendered node elements

            while (current) {
                const nodeDiv = document.createElement('div');
                nodeDiv.classList.add('node');
                if (current === linkedList.head) {
                    nodeDiv.classList.add('head-node');
                }
                nodeDiv.textContent = current.value;
                nodeDiv.dataset.value = current.value; // Store value for search/delete
                listNodesContainer.appendChild(nodeDiv);
                nodeElements.push(nodeDiv);
                current = current.next;
            }

            // After all nodes are in the DOM, draw arrows
            setTimeout(() => { // Use setTimeout to ensure elements are rendered and have dimensions
                for (let i = 0; i < nodeElements.length - 1; i++) {
                    const startElement = nodeElements[i];
                    const endElement = nodeElements[i + 1];
                    drawArrow(startElement, endElement);
                }
            }, 0); // Small delay
        }

        function drawArrow(startElement, endElement) {
            const containerRect = listNodesContainer.getBoundingClientRect();
            const startRect = startElement.getBoundingClientRect();
            const endRect = endElement.getBoundingClientRect();

            // Calculate start and end points relative to the SVG container
            // Start point: middle right of the start element
            const startX = startRect.right - containerRect.left;
            const startY = startRect.top + startRect.height / 2 - containerRect.top;

            // End point: middle left of the end element, adjusted for arrow head
            const endX = endRect.left - containerRect.left - 10; // Adjust for marker-end width
            const endY = endRect.top + endRect.height / 2 - containerRect.top;

            const line = document.createElementNS('http://www.w3.org/2000/svg', 'line');
            line.setAttribute('x1', startX);
            line.setAttribute('y1', startY);
            line.setAttribute('x2', endX);
            line.setAttribute('y2', endY);
            line.setAttribute('class', 'arrow');

            svgArrows.appendChild(line);
        }

        function clearInputs() {
            document.getElementById('insertValue').value = '';
            document.getElementById('deleteValue').value = '';
            document.getElementById('searchValue').value = '';
        }

        function insertAtHead() {
            const valueInput = document.getElementById('insertValue');
            const value = parseInt(valueInput.value);
            if (isNaN(value)) {
                alert('Please enter a valid number for insertion.');
                return;
            }
            linkedList.insertAtHead(value);
            renderList();
            clearInputs();
        }

        function insertAtTail() {
            const valueInput = document.getElementById('insertValue');
            const value = parseInt(valueInput.value);
            if (isNaN(value)) {
                alert('Please enter a valid number for insertion.');
                return;
            }
            linkedList.insertAtTail(value);
            renderList();
            clearInputs();
        }

        function deleteByValue() {
            const valueInput = document.getElementById('deleteValue');
            const value = parseInt(valueInput.value);
            if (isNaN(value)) {
                alert('Please enter a valid number for deletion.');
                return;
            }
            const deleted = linkedList.deleteByValue(value);
            if (!deleted) {
                alert(`Value ${value} not found in the list.`);
            }
            renderList();
            clearInputs();
        }

        function searchByValue() {
            const valueInput = document.getElementById('searchValue');
            const value = parseInt(valueInput.value);
            if (isNaN(value)) {
                alert('Please enter a valid number for search.');
                return;
            }

            // Remove any previous highlights
            document.querySelectorAll('.node.found').forEach(node => {
                node.classList.remove('found');
            });

            const foundNode = linkedList.search(value);
            if (foundNode) {
                // Find the DOM element corresponding to the found node
                const nodeElements = document.querySelectorAll('.node');
                for (const element of nodeElements) {
                    // Use dataset.value for comparison as textContent might be 'Value' or 'Value ->'
                    if (parseInt(element.dataset.value) === value) {
                        element.classList.add('found');
                        element.scrollIntoView({ behavior: 'smooth', block: 'nearest', inline: 'center' }); // Scroll to the found node
                        break;
                    }
                }
            } else {
                alert(`Value ${value} not found in the list.`);
            }
            clearInputs();
        }

        // Initial render
        renderList();
    </script>
</body>
</html>
