            const value = parseInt(deleteValueInput.value);
            if (isNaN(value)) {
                showErrorMessage('Please enter a valid number to delete.');
                return;
            }
            const deleted = linkedList.deleteByValue(value);
            if (!deleted) {
                showErrorMessage(`Node with value ${value} not found.`);
            }
            renderList();
            deleteValueInput.value = ''; // Clear input
        });

        searchBtn.addEventListener('click', () => {
            const value = parseInt(searchValueInput.value);
            if (isNaN(value)) {
                showErrorMessage('Please enter a valid number to search.');
                return;
            }
            const result = linkedList.search(value);
            if (result) {
                renderList(value); // Rerender with the found node highlighted
                showErrorMessage(`Node with value ${value} found!`);
            } else {
                renderList(); // Rerender without highlight if not found
                showErrorMessage(`Node with value ${value} not found.`);
            }
            searchValueInput.value = ''; // Clear input
        });

        // Initial render
        renderList();

    </script>
</body>
