                const newNode = new Node(value);
                if (this.isEmpty()) {
                    this.head = newNode;
                    return;
                }
                let current = this.head;
                while (current.next !== null) {
                    current = current.next;
                }
                current.next = newNode;
            }

            deleteByValue(value) {
                if (this.isEmpty()) {
                    return false; // List is empty
                }

                // If head needs to be deleted
                if (this.head.value === value) {
                    this.head = this.head.next;
                    return true;
                }

                let current = this.head;
                let prev = null;
                while (current !== null && current.value !== value) {
                    prev = current;
                    current = current.next;
                }

                if (current === null) {
                    return false; // Value not found
                }

                // Skip the current node (delete it)
                prev.next = current.next;
                return true;
            }

            search(value) {
                if (this.isEmpty()) {
                    return null;
                }
                let current = this.head;
                while (current !== null) {
                    if (current.value === value) {
                        return current; // Found the node
                    }
                    current = current.next;
                }
                return null; // Not found
            }
        }

        // ------------------------------------------
        // 2. DOM Elements and Initialization
        // ------------------------------------------

        const linkedList = new LinkedList();
        const linkedListContainer = document.getElementById('linkedListContainer');
        const nodeValueInput = document.getElementById('nodeValue');
        const insertHeadBtn = document.getElementById('insertHeadBtn');
        const insertTailBtn = document.getElementById('insertTailBtn');
        const deleteBtn = document.getElementById('deleteBtn');
        const searchBtn = document.getElementById('searchBtn');
        const messageDiv = document.getElementById('message');

        // ------------------------------------------
        // 3. Visualization Logic
        // ------------------------------------------

        function showMessage(text, type = 'success', duration = 3000) {
            messageDiv.textContent = text;
            messageDiv.className = `show ${type}`; // Add 'show' class to make it visible
            setTimeout(() => {
                messageDiv.classList.remove('show');
                // Optionally clear text after fade out
                setTimeout(() => messageDiv.textContent = '', 300);
            }, duration);
        }

        function clearInput() {
            nodeValueInput.value = '';
        }

        async function renderList() {
            linkedListContainer.innerHTML = ''; // Clear existing visualization

            if (linkedList.isEmpty()) {
                const emptyMessage = document.createElement('div');
                emptyMessage.className = 'empty-list-message';
                emptyMessage.textContent = 'List is Empty';
                linkedListContainer.appendChild(emptyMessage);
                return;
            }

            let current = linkedList.head;
            while (current !== null) {
                // Create node element
                const nodeElement = document.createElement('div');
                nodeElement.classList.add('node');
                nodeElement.textContent = current.value;
                nodeElement.dataset.value = current.value; // Store value for easy access

                linkedListContainer.appendChild(nodeElement);

                if (current.next !== null) {
                    // Create arrow element
                    const arrowElement = document.createElement('div');
                    arrowElement.classList.add('arrow');
                    linkedListContainer.appendChild(arrowElement);
                }
                current = current.next;
            }

            // Add NULL pointer at the end
            const nullPointer = document.createElement('div');
            nullPointer.classList.add('null-pointer');
            nullPointer.textContent = 'NULL';
            linkedListContainer.appendChild(nullPointer);
        }

        // ------------------------------------------
        // 4. Event Handlers
        // ------------------------------------------

        insertHeadBtn.addEventListener('click', () => {
            const value = parseInt(nodeValueInput.value);
            if (isNaN(value)) {
                showMessage('Please enter a valid number.', 'error');
                return;
            }
            linkedList.insertAtHead(value);
            renderList();
            showMessage(`Inserted ${value} at head.`);
            clearInput();
        });

        insertTailBtn.addEventListener('click', () => {
            const value = parseInt(nodeValueInput.value);
            if (isNaN(value)) {
                showMessage('Please enter a valid number.', 'error');
                return;
            }
            linkedList.insertAtTail(value);
            renderList();
            showMessage(`Inserted ${value} at tail.`);
            clearInput();
        });

        deleteBtn.addEventListener('click', async () => {
            const value = parseInt(nodeValueInput.value);
            if (isNaN(value)) {
                showMessage('Please enter a valid number to delete.', 'error');
                return;
            }

            const nodeToDelete = linkedListContainer.querySelector(`.node[data-value="${value}"]`);

            if (nodeToDelete) {
                // Add deleted class for visual effect
                nodeToDelete.classList.add('deleted');
                showMessage(`Deleting ${value}...`, 'success');

                // Wait for the deletion animation to complete
                await new Promise(resolve => setTimeout(resolve, 500));
            }

            const deleted = linkedList.deleteByValue(value);
            if (deleted) {
                renderList();
                showMessage(`Deleted ${value}.`);
            } else {
                renderList(); // Re-render in case it was the only node or to clear deleted state if not found
                showMessage(`${value} not found in the list.`, 'error');
            }
            clearInput();
        });

        searchBtn.addEventListener('click', async () => {
            const value = parseInt(nodeValueInput.value);
            if (isNaN(value)) {
                showMessage('Please enter a valid number to search.', 'error');
                return;
            }

            // Remove any previous highlights
            document.querySelectorAll('.node.highlight').forEach(node => {
                node.classList.remove('highlight');
            });

            const foundNodeLogical = linkedList.search(value);

            if (foundNodeLogical) {
                // Find the corresponding DOM element
                const foundNodeElement = linkedListContainer.querySelector(`.node[data-value="${value}"]`);
                if (foundNodeElement) {
                    foundNodeElement.classList.add('highlight');
                    showMessage(`Found ${value}!`, 'success');

                    // Remove highlight after a delay
                    setTimeout(() => {
                        foundNodeElement.classList.remove('highlight');
                    }, 2000);
                }
            } else {
                showMessage(`${value} not found in the list.`, 'error');
            }
            clearInput();
        });

        // Initial render when the page loads
        renderList();
    </script>
</body>
</html>
```

