    <script>
        // --- Linked List Data Structure ---
        class Node {
            constructor(value) {
                this.value = value;
                this.next = null;
            }
        }

        class LinkedList {
            constructor() {
                this.head = null;
            }

            insertAtHead(value) {
                const newNode = new Node(value);
                newNode.next = this.head;
                this.head = newNode;
                return newNode; // Return for highlighting
            }

            insertAtTail(value) {
                const newNode = new Node(value);
                if (!this.head) {
                    this.head = newNode;
                    return newNode;
                }
                let current = this.head;
                while (current.next) {
                    current = current.next;
                }
                current.next = newNode;
                return newNode; // Return for highlighting
            }

            deleteByValue(value) {
                if (!this.head) {
                    return null; // List is empty
                }

                if (this.head.value === value) {
                    const deletedNode = this.head;
                    this.head = this.head.next;
                    return deletedNode;
                }

                let current = this.head;
                while (current.next && current.next.value !== value) {
                    current = current.next;
                }

                if (current.next && current.next.value === value) {
                    const deletedNode = current.next;
                    current.next = current.next.next;
                    return deletedNode;
                }
                return null; // Value not found
            }

            searchByValue(value) {
                let current = this.head;
                const foundNodes = [];
                while (current) {
                    if (current.value === value) {
                        foundNodes.push(current);
                    }
                    current = current.next;
                }
                return foundNodes;
            }

            toArray() {
                const arr = [];
                let current = this.head;
                while (current) {
                    arr.push(current);
                    current = current.next;
                }
                return arr;
            }

            clear() {
                this.head = null;
            }
        }

        const list = new LinkedList();

        // --- DOM Elements ---
        const listContainer = document.getElementById('listContainer');
        const listSvg = document.getElementById('listSvg');
        const headPointerText = document.getElementById('headPointerText');
        const headArrowSvg = document.getElementById('headArrowSvg');

        const NODE_WIDTH = 80;
        const NODE_HEIGHT = 60;
        const NODE_MARGIN_RIGHT = 40; // Space for the arrow
        const TOTAL_NODE_SPACING = NODE_WIDTH + NODE_MARGIN_RIGHT;
        const ARROW_OFFSET_X = NODE_WIDTH / 2; // Arrow starts from center-right of node

        // --- Rendering Functions ---
        function renderList(highlightNode = null, searchNodes = []) {
            // Clear previous rendering
            listContainer.innerHTML = '';
            listSvg.innerHTML = '';
            headArrowSvg.innerHTML = '';

            const nodes = list.toArray();

            // Render Head Pointer
            if (list.head) {
                headPointerText.textContent = 'Head: ' + list.head.value;
                // Draw head arrow to first node
                const headArrowPath = document.createElementNS('http://www.w3.org/2000/svg', 'path');
                headArrowPath.setAttribute('d', `M0,0 V30 H${TOTAL_NODE_SPACING / 2} V60`); // Example path, adjusted dynamically
                headArrowPath.setAttribute('marker-end', 'url(#arrowhead-head)');
                headArrowSvg.appendChild(headArrowPath);

                // Adjust head arrow position and path
                requestAnimationFrame(() => {
                    const firstNodeEl = listContainer.querySelector('.node');
                    if (firstNodeEl) {
                        const headPointerRect = headPointerText.getBoundingClientRect();
                        const firstNodeRect = firstNodeEl.getBoundingClientRect();
                        const containerRect = listContainer.getBoundingClientRect();
                        const headArrowSvgRect = headArrowSvg.getBoundingClientRect();

                        const startX = headArrowSvgRect.width / 2; // Center of headArrowSvg
                        const startY = 0; // Top of headArrowSvg

                        const endX = (firstNodeRect.left + NODE_WIDTH / 2) - headArrowSvgRect.left;
                        const endY = (firstNodeRect.top - (headArrowSvgRect.top + headArrowSvgRect.height)) + (NODE_HEIGHT / 2);

                        // Calculate path for a slightly curved or angled arrow from head text to node
                        // For simplicity, let's make it a vertical line down, then horizontal, then vertical up to the node.
                        // We need the headArrowSvg to be positioned correctly relative to the first node.
                        // Let's make it point directly to the top center of the first node from a point above it.

                        // The headPointerText is positioned absolutely relative to visualization-container.
                        // The headArrowSvg is also positioned absolutely relative to visualization-container.
                        // We want the arrow to go from below headPointerText to the top-center of the first node.

                        const headTextBottomY = headPointerText.offsetTop + headPointerText.offsetHeight;
                        const firstNodeTopY = firstNodeEl.offsetTop;
                        const firstNodeCenterX = firstNodeEl.offsetLeft + NODE_WIDTH / 2;

                        // Start point for arrow within headArrowSvg's coordinate system
                        const arrowStartRelX = headArrowSvg.clientWidth / 2;
                        const arrowStartRelY = headPointerText.offsetHeight + 5; // A little below the text

                        // End point for arrow within headArrowSvg's coordinate system
                        const arrowEndRelX = firstNodeCenterX - headArrowSvg.offsetLeft;
                        const arrowEndRelY = firstNodeTopY - headArrowSvg.offsetTop + (NODE_HEIGHT / 2);

                        // Simple vertical then horizontal arrow
                        headArrowPath.setAttribute('d', `M ${arrowStartRelX}, ${arrowStartRelY}
                                                          V ${arrowEndRelY - 10}
                                                          H ${arrowEndRelX}
                                                          V ${arrowEndRelY}`);
                    }
                });


            } else {
                headPointerText.textContent = 'Head: null';
            }

            // Render Nodes
            nodes.forEach((node, index) => {
                const nodeEl = document.createElement('div');
                nodeEl.classList.add('node');
                nodeEl.id = `node-${node.value}-${index}`; // Unique ID for each node instance

                const valueEl = document.createElement('div');
                valueEl.classList.add('node-value');
                valueEl.textContent = node.value;

                nodeEl.appendChild(valueEl);
                listContainer.appendChild(nodeEl);

                // Apply highlighting
                if (node === highlightNode) {
                    nodeEl.classList.add('highlight-new');
                    nodeEl.addEventListener('animationend', () => {
                        nodeEl.classList.remove('highlight-new');
                    }, { once: true });
                }
                if (searchNodes.includes(node)) {
                    nodeEl.classList.add('highlight-search');
                }
            });

            // Render Arrows between nodes
            requestAnimationFrame(() => { // Ensure nodes are rendered and positioned before drawing arrows
                const renderedNodes = listContainer.querySelectorAll('.node');
                if (renderedNodes.length === 0) return;

                // Update head arrow if list is not empty
                if (list.head) {
                    const firstNodeEl = renderedNodes[0];
                    const headTextRect = headPointerText.getBoundingClientRect();
                    const firstNodeRect = firstNodeEl.getBoundingClientRect();
                    const containerRect = listContainer.getBoundingClientRect(); // visualization-container
                    const headArrowSvgRect = headArrowSvg.getBoundingClientRect();

                    const headStartX = headArrowSvgRect.width / 2;
                    const headStartY = headTextRect.height + 5; // Below head text, within headArrowSvg coords

                    const headEndX = (firstNodeRect.left + firstNodeRect.width / 2) - headArrowSvgRect.left;
                    const headEndY = (firstNodeRect.top + firstNodeRect.height / 2) - headArrowSvgRect.top;

                    const path = document.createElementNS('http://www.w3.org/2000/svg', 'path');
                    // Draw a path from below the head text, then down, then right to the node's top-center
                    path.setAttribute('d', `M ${headStartX}, ${headStartY}
                                            V ${headEndY - (firstNodeRect.height / 2) - 10}
                                            H ${headEndX}
                                            V ${headEndY}`);
                    path.setAttribute('marker-end', 'url(#arrowhead-head)');
                    headArrowSvg.appendChild(path);
                }


                renderedNodes.forEach((nodeEl, index) => {
                    if (index < renderedNodes.length - 1) { // Not the last node
                        const nextNodeEl = renderedNodes[index + 1];

                        const startX = nodeEl.offsetLeft + NODE_WIDTH; // Right edge of current node
                        const startY = nodeEl.offsetTop + NODE_HEIGHT / 2; // Middle of current node

                        const endX = nextNodeEl.offsetLeft; // Left edge of next node
                        const endY = nextNodeEl.offsetTop + NODE_HEIGHT / 2; // Middle of next node

                        const arrowLine = document.createElementNS('http://www.w3.org/2000/svg', 'line');
                        arrowLine.setAttribute('x1', startX);
                        arrowLine.setAttribute('y1', startY);
                        arrowLine.setAttribute('x2', endX);
                        arrowLine.setAttribute('y2', endY);
                        arrowLine.setAttribute('marker-end', 'url(#arrowhead)');
                        listSvg.appendChild(arrowLine);
                    } else {
                        // Last node's pointer (to null)
                        const nullPointerText = document.createElement('div');
                        nullPointerText.classList.add('node-pointer-text');
                        nullPointerText.textContent = 'null';
                        nullPointerText.style.position = 'absolute';
                        nullPointerText.style.left = `${nodeEl.offsetLeft + NODE_WIDTH + (NODE_MARGIN_RIGHT / 2) - 15}px`;
                        nullPointerText.style.top = `${nodeEl.offsetTop + NODE_HEIGHT / 2 - 10}px`;
                        listContainer.appendChild(nullPointerText);
                    }
                });
            });
        }

        // --- Control Handlers ---
        function insertAtHead() {
            const value = parseInt(document.getElementById('insertValue').value);
            if (isNaN(value)) {
                alert('Please enter a valid number for insertion.');
                return;
            }
            const newNode = list.insertAtHead(value);
            renderList(newNode);
            document.getElementById('insertValue').value = value + 1; // Increment for next insertion
        }

        function insertAtTail() {
            const value = parseInt(document.getElementById('insertValue').value);
            if (isNaN(value)) {
                alert('Please enter a valid number for insertion.');
                return;
            }
            const newNode = list.insertAtTail(value);
            renderList(newNode);
            document.getElementById('insertValue').value = value + 1; // Increment for next insertion
        }

        function deleteByValue() {
            const value = parseInt(document.getElementById('deleteValue').value);
            if (isNaN(value)) {
                alert('Please enter a valid number for deletion.');
                return;
            }
            const deletedNodeInstance = list.deleteByValue(value);
            if (deletedNodeInstance) {
                // Find the corresponding DOM element
                const nodesInDOM = listContainer.querySelectorAll('.node');
                let domNodeToDelete = null;
                // Since our DOM nodes are recreated, we need to find the one that *was* associated
                // with the value. A simpler approach for visualization is to re-render after a delay.
                // For a more complex viz, each DOM node would have a reference to its JS Node object.
                // For now, we'll just re-render.
                renderList(); // Render immediately to reflect structural change
            } else {
                alert(`Value ${value} not found in the list.`);
            }
        }

        function searchByValue() {
            const value = parseInt(document.getElementById('searchValue').value);
            if (isNaN(value)) {
                alert('Please enter a valid number for search.');
                return;
            }
            // Clear previous search highlights
            listContainer.querySelectorAll('.node.highlight-search').forEach(el => {
                el.classList.remove('highlight-search');
            });

            const foundNodes = list.searchByValue(value);
            if (foundNodes.length > 0) {
                renderList(null, foundNodes); // Re-render with search highlight
            } else {
                alert(`Value ${value} not found in the list.`);
                renderList(); // Re-render to ensure no old highlights remain
            }
        }

        function clearList() {
            list.clear();
            renderList();
        }

        // Initial render
        document.addEventListener('DOMContentLoaded', () => {
            renderList();
            // Add some initial nodes for testing
            list.insertAtTail(10);
            list.insertAtTail(20);
            list.insertAtTail(30);
            list.insertAtHead(5);
            renderList();
        });

        // Re-render on window resize to adjust arrow positions if needed
        window.addEventListener('resize', () => {
             renderList();
        });

    </script>
</body>
