            }
        }

        async function searchByValue() {
            const value = getValue();
            if (value !== null) {
                await linkedList.searchByValue(value);
            }
        }

        function clearList() {
            if (confirm("Are you sure you want to clear the entire list?")) {
                linkedList.clear();
            }
        }

        // Handle window resize to redraw arrows
        window.addEventListener('resize', () => {
            linkedList._updateVisualization();
        });

    </script>
