                pointerBox.setAttribute('x', NODE_WIDTH - POINTER_BOX_WIDTH);
                pointerBox.setAttribute('y', 0);
                pointerBox.setAttribute('width', POINTER_BOX_WIDTH);
                pointerBox.setAttribute('height', NODE_HEIGHT);
                pointerBox.setAttribute('rx', 5);
                pointerBox.setAttribute('ry', 5);
                pointerBox.classList.add('node-box');
                nodeGroup.appendChild(pointerBox);

                // Pointer Label (optional, for visual clarity inside pointer box)
                const pointerLabel = document.createElementNS(SVG_NS, 'text');
                pointerLabel.setAttribute('x', NODE_WIDTH - POINTER_BOX_WIDTH / 2);
                pointerLabel.setAttribute('y', NODE_HEIGHT / 2);
                pointerLabel.classList.add('node-pointer-label');
                pointerLabel.textContent = 'next';
                // nodeGroup.appendChild(pointerLabel); // Uncomment to show 'next' label

                svg.appendChild(nodeGroup);

                // Add arrow if not the last node
                if (current.next) {
                    const arrow = document.createElementNS(SVG_NS, 'path');
                    const startPointX = x + NODE_WIDTH;
                    const startPointY = y;
                    const endPointX = x + NODE_WIDTH + NODE_SPACING;
                    const endPointY = y;

                    arrow.setAttribute('d', `M ${startPointX} ${startPointY} H ${endPointX - 10}`); // Subtract 10 for arrowhead
                    arrow.classList.add('arrow');
                    svg.appendChild(arrow);
                } else {
                    // Display NULL for the last node
                    const nullText = document.createElementNS(SVG_NS, 'text');
                    nullText.setAttribute('x', x + NODE_WIDTH + 10);
                    nullText.setAttribute('y', y);
                    nullText.classList.add('null-label');
                    nullText.textContent = 'NULL';
                    svg.appendChild(nullText);
                }

                current = current.next;
                x += NODE_WIDTH + NODE_SPACING;
                nodeCount++;
            }

            // Adjust SVG viewBox width dynamically
            const requiredWidth = x + (head ? 100 : 0); // Add some padding
            svg.setAttribute('viewBox', `0 0 ${Math.max(requiredWidth, 500)} ${svg.getAttribute('height')}`);
        }

        function insertAtHead() {
            const value = nodeValueInput.value.trim();
            if (value === "") {
                alert("Please enter a value for the node.");
                return;
            }

            const newNode = new Node(value);
            newNode.next = head;
            head = newNode;
            nodeValueInput.value = "";
            renderList();
            // Add a temporary animation class to the first node
            const firstNodeGroup = svg.querySelector('.node-group');
            if (firstNodeGroup) {
                firstNodeGroup.classList.add('new-node-animation');
                setTimeout(() => firstNodeGroup.classList.remove('new-node-animation'), 500);
            }
        }

        function insertAtTail() {
            const value = nodeValueInput.value.trim();
            if (value === "") {
                alert("Please enter a value for the node.");
                return;
            }

            const newNode = new Node(value);
            if (!head) {
                head = newNode;
            } else {
                let current = head;
                while (current.next) {
                    current = current.next;
                }
                current.next = newNode;
            }
            nodeValueInput.value = "";
            renderList();
            // Add a temporary animation class to the last node
            const nodeGroups = svg.querySelectorAll('.node-group');
            const lastNodeGroup = nodeGroups[nodeGroups.length - 1];
            if (lastNodeGroup) {
                lastNodeGroup.classList.add('new-node-animation');
                setTimeout(() => lastNodeGroup.classList.remove('new-node-animation'), 500);
            }
        }

        async function deleteByValue() {
            const valueToDelete = nodeValueInput.value.trim();
            if (valueToDelete === "") {
                alert("Please enter a value to delete.");
                return;
            }

            clearHighlights();
            let current = head;
            let prev = null;
            let currentIndex = 0;

            const nodeGroups = svg.querySelectorAll('.node-group');

            while (current) {
                const currentNodeBox = nodeGroups[currentIndex] ? nodeGroups[currentIndex].querySelector('.node-box') : null;
                const currentArrow = nodeGroups[currentIndex] ? svg.querySelectorAll('.arrow')[currentIndex] : null;

                if (currentNodeBox) {
                    currentNodeBox.classList.add('highlighted');
                }
                if (currentArrow) {
                    currentArrow.classList.add('highlighted-arrow');
                    currentArrow.setAttribute('marker-end', 'url(#highlightedArrowhead)');
                }

                await new Promise(resolve => animationTimeout = setTimeout(resolve, 500)); // Pause for visualization

                if (current.value === valueToDelete) {
                    if (prev === null) { // Deleting head
                        head = current.next;
                    } else {
                        prev.next = current.next;
                    }
                    nodeValueInput.value = "";
                    renderList(); // Re-render the list after deletion
                    alert(`Node with value '${valueToDelete}' deleted.`);
                    return;
                }

                // Remove highlight if not deleted
                if (currentNodeBox) {
                    currentNodeBox.classList.remove('highlighted');
                }
                if (currentArrow) {
                    currentArrow.classList.remove('highlighted-arrow');
                    currentArrow.setAttribute('marker-end', 'url(#arrowhead)');
                }

                prev = current;
                current = current.next;
                currentIndex++;
            }

            alert(`Node with value '${valueToDelete}' not found.`);
            nodeValueInput.value = "";
            renderList(); // Ensure state is clean
        }

        async function search() {
            const valueToSearch = nodeValueInput.value.trim();
            if (valueToSearch === "") {
                alert("Please enter a value to search.");
                return;
            }

            clearHighlights();
            let current = head;
            let currentIndex = 0;
            let found = false;

            const nodeGroups = svg.querySelectorAll('.node-group');

            while (current) {
                const currentNodeBox = nodeGroups[currentIndex] ? nodeGroups[currentIndex].querySelector('.node-box') : null;
                const currentArrow = nodeGroups[currentIndex] ? svg.querySelectorAll('.arrow')[currentIndex] : null;

                if (currentNodeBox) {
                    currentNodeBox.classList.add('highlighted');
                }
                if (currentArrow) {
                    currentArrow.classList.add('highlighted-arrow');
                    currentArrow.setAttribute('marker-end', 'url(#highlightedArrowhead)');
                }

                await new Promise(resolve => animationTimeout = setTimeout(resolve, 500)); // Pause for visualization

                if (current.value === valueToSearch) {
                    found = true;
                    alert(`Node with value '${valueToSearch}' found!`);
                    break;
                }

                // Remove highlight if not found yet
                if (currentNodeBox) {
                    currentNodeBox.classList.remove('highlighted');
                }
                if (currentArrow) {
                    currentArrow.classList.remove('highlighted-arrow');
                    currentArrow.setAttribute('marker-end', 'url(#arrowhead)');
                }

                current = current.next;
                currentIndex++;
            }

            if (!found) {
                alert(`Node with value '${valueToSearch}' not found.`);
            }
            nodeValueInput.value = "";
            clearHighlights(); // Clear all highlights after search is complete
        }

        function clearList() {
            head = null;
            renderList();
            alert("Linked list cleared!");
        }

        // Initial render
        renderList();

    </script>
</body>
</html>
